     1→/**
     2→ * GiteaAdapter — StorageAdapter backed by the Gitea API.
     3→ *
     4→ * Uses the Gitea Contents API to read/write files in a remote repository.
     5→ * Requires a base URL and API token for authentication.
     6→ */
     7→
     8→import type { StorageAdapter } from './adapter.js'
     9→
    10→export interface GiteaAdapterOptions {
    11→  baseUrl: string
    12→  owner: string
    13→  repo: string
    14→  token: string
    15→  branch?: string
    16→}
    17→
    18→export class GiteaAdapter implements StorageAdapter {
    19→  private readonly baseUrl: string
    20→  private readonly owner: string
    21→  private readonly repo: string
    22→  private readonly token: string
    23→  private readonly branch: string
    24→
    25→  constructor(options: GiteaAdapterOptions) {
    26→    this.baseUrl = options.baseUrl.replace(/\/+$/, '')
    27→    this.owner = options.owner
    28→    this.repo = options.repo
    29→    this.token = options.token
    30→    this.branch = options.branch ?? 'main'
    31→  }
    32→
    33→  async writeFile(path: string, content: string | Buffer): Promise<void> {
    34→    const base64Content = Buffer.from(content).toString('base64')
    35→    const normalizedPath = normalizePath(path)
    36→    const existing = await this.getFileSha(normalizedPath)
    37→
    38→    const body: Record<string, unknown> = {
    39→      content: base64Content,
    40→      message: `update ${normalizedPath}`,
    41→      branch: this.branch,
    42→    }
    43→    if (existing) {
    44→      body['sha'] = existing
    45→    }
    46→
    47→    const method = existing ? 'PUT' : 'POST'
    48→    const url = `${this.baseUrl}/api/v1/repos/${this.owner}/${this.repo}/contents/${normalizedPath}`
    49→
    50→    const response = await fetch(url, {
    51→      method,
    52→      headers: this.headers(),
    53→      body: JSON.stringify(body),
    54→    })
    55→
    56→    if (!response.ok) {
    57→      const text = await response.text()
    58→      throw new Error(`Gitea API ${method} ${normalizedPath} failed (${response.status}): ${text}`)
    59→    }
    60→  }
    61→
    62→  async readFile(path: string): Promise<string> {
    63→    const normalizedPath = normalizePath(path)
    64→    const url = `${this.baseUrl}/api/v1/repos/${this.owner}/${this.repo}/contents/${normalizedPath}?ref=${this.branch}`
    65→
    66→    const response = await fetch(url, { headers: this.headers() })
    67→    if (!response.ok) {
    68→      throw new Error(`Gitea API GET ${normalizedPath} failed (${response.status})`)
    69→    }
    70→
    71→    const data = (await response.json()) as { content?: string; encoding?: string }
    72→    if (data.encoding === 'base64' && data.content) {
    73→      return Buffer.from(data.content, 'base64').toString('utf-8')
    74→    }
    75→    return data.content ?? ''
    76→  }
    77→
    78→  async exists(path: string): Promise<boolean> {
    79→    const normalizedPath = normalizePath(path)
    80→    const url = `${this.baseUrl}/api/v1/repos/${this.owner}/${this.repo}/contents/${normalizedPath}?ref=${this.branch}`
    81→
    82→    const response = await fetch(url, { headers: this.headers() })
    83→    return response.ok
    84→  }
    85→
    86→  async mkdir(_path: string): Promise<void> {
    87→    // Gitea auto-creates directories when files are written
    88→  }
    89→
    90→  async copyFile(source: string, destination: string): Promise<void> {
    91→    const content = await this.readFile(source)
    92→    await this.writeFile(destination, content)
    93→  }
    94→
    95→  async appendFile(path: string, content: string): Promise<void> {
    96→    let existing = ''
    97→    if (await this.exists(path)) {
    98→      existing = await this.readFile(path)
    99→    }
   100→    await this.writeFile(path, existing + content)
   101→  }
   102→
   103→  private headers(): Record<string, string> {
   104→    return {
   105→      'Authorization': `token ${this.token}`,
   106→      'Content-Type': 'application/json',
   107→      'Accept': 'application/json',
   108→    }
   109→  }
   110→
   111→  private async getFileSha(path: string): Promise<string | null> {
   112→    const url = `${this.baseUrl}/api/v1/repos/${this.owner}/${this.repo}/contents/${path}?ref=${this.branch}`
   113→    const response = await fetch(url, { headers: this.headers() })
   114→    if (!response.ok) return null
   115→    const data = (await response.json()) as { sha?: string }
   116→    return data.sha ?? null
   117→  }
   118→}
   119→
   120→function normalizePath(path: string): string {
   121→  return path.replace(/\\/g, '/').replace(/^\/+/, '')
   122→}
   123→

